create table dirkspzm32.pzm_schicht_modelle (
    sm_name                varchar2(100 char) not null enable,
    sm_anz_wochen          number(*, 0) default 1 not null enable,
    sm_kurzname            varchar2(10 char),
    flex_max_std_pro_woche number(*, 12),
    d_arb_std_pro_tag      number(*, 12),
    calc_basis             varchar2(20 char) default 'FESTZ' not null enable,
    standard_aa_id         number(*, 0),
    kappung_me_ab_flx_std  number(*, 12),
    kappung_te_ab_flx_std  number(*, 12),
    kappung_schicht_ende   varchar2(1 char) default 'F' not null enable,
    beginn_gutschr_min     number(*, 12),
    ende_gutschr_min       number(*, 12),
    rastermin              number(*, 0),
    created_date           date default sysdate not null enable,
    created_login_id       number(*, 0) default - 1 not null enable,
    last_change_date       date,
    last_change_login_id   number(*, 0)
);

alter table dirkspzm32.pzm_schicht_modelle
    add constraint pk_sm_name primary key ( sm_name )
        using index enable;


